class Pair:
    """A Scheme pair: a first element and a second (the rest of the list)."""
    def __init__(self, first, second):
        self.first = first
        self.second = second

    def map(self, fn):
        """Return a new Pair with fn applied to every element of this list."""
        rest = self.second.map(fn) if isinstance(self.second, Pair) else self.second
        return Pair(fn(self.first), rest)

    def __repr__(self):
        return "Pair({0}, {1})".format(repr(self.first), repr(self.second))


nil = ()  # the empty list, which ends a well-formed Scheme list


def scheme_list(*items):
    """Build a Scheme list (a Pair chain ending in nil) from Python items."""
    result = nil
    for item in reversed(items):
        result = Pair(item, result)
    return result


class Frame:
    """An environment: a table of bindings plus a parent frame (None at global)."""
    def __init__(self, parent=None):
        self.bindings = {}
        self.parent = parent

    def define(self, symbol, value):
        self.bindings[symbol] = value

    def lookup(self, symbol):
        if symbol in self.bindings:
            return self.bindings[symbol]
        if self.parent is not None:
            return self.parent.lookup(symbol)
        raise NameError(symbol)


class LambdaProcedure:
    """A user-defined procedure: parameter names, a body expression, a parent frame."""
    def __init__(self, params, body, env):
        self.params = params
        self.body = body
        self.env = env


def scheme_eval(expr, env):
    """Evaluate Scheme expression expr (Python data) in environment env."""
    if isinstance(expr, str):              # a symbol: look it up
        return env.lookup(expr)
    if not isinstance(expr, Pair):         # a self-evaluating atom (number)
        return expr
    first, rest = expr.first, expr.second  # otherwise a combination
    if first == "define":
        name = rest.first
        value = scheme_eval(rest.second.first, env)
        env.define(name, value)
        return None
    procedure = scheme_eval(first, env)
    args = rest.map(lambda operand: scheme_eval(operand, env))
    return scheme_apply(procedure, args, env)


def scheme_apply(procedure, args, env):
    """Apply a procedure to an argument list (a Pair chain ending in nil)."""
    arg_values = []
    while args is not nil:
        arg_values.append(args.first)
        args = args.second
    if isinstance(procedure, LambdaProcedure):
        call_frame = Frame(procedure.env)
        params = procedure.params
        i = 0
        while params is not nil:
            call_frame.define(params.first, arg_values[i])
            params = params.second
            i += 1
        return scheme_eval(procedure.body, call_frame)
    return procedure(*arg_values)          # a primitive: a Python function


def make_global():
    """A fresh global frame with a few primitive procedures bound."""
    g = Frame()
    g.define("+", lambda a, b: a + b)
    g.define("-", lambda a, b: a - b)
    g.define("*", lambda a, b: a * b)
    g.define("=", lambda a, b: a == b)
    return g
